import{_ as e,c as a,o,R as n}from"./chunks/framework.bdd825cc.js";const u=JSON.parse('{"title":"语义化版本","description":"","frontmatter":{},"headers":[],"relativePath":"blogs/2023/03/semver.md","filePath":"blogs/2023/03/semver.md","lastUpdated":1683265338000}'),r={name:"blogs/2023/03/semver.md"},s=n(`<h1 id="语义化版本" tabindex="-1">语义化版本 <a class="header-anchor" href="#语义化版本" aria-label="Permalink to &quot;语义化版本&quot;">​</a></h1><ul><li>语义化版本 - 本篇</li><li><a href="./conventional-commits.html">约定式提交</a></li><li><a href="./changelog.html">改动日志</a></li></ul><p><a href="https://semver.org/lang/zh-CN/" target="_blank" rel="noreferrer">语义化版本</a> 是一个常见的术语，相信大部分人都或多或少听过。可能与大部分人不同，我在了解语义化版本后，摆脱了刀耕火种的道路，走上了遵循规范、约定式优先的开发道路。因此，语义化版本对我有着特殊的意义。</p><h2 id="什么是语义化版本" tabindex="-1">什么是语义化版本 <a class="header-anchor" href="#什么是语义化版本" aria-label="Permalink to &quot;什么是语义化版本&quot;">​</a></h2><p>简而言之，语义化版本是用于解决版本号混乱的方案。它定义了一组规则，来控制版本号的变化。</p><h2 id="基本格式" tabindex="-1">基本格式 <a class="header-anchor" href="#基本格式" aria-label="Permalink to &quot;基本格式&quot;">​</a></h2><p>最基本的语义化版本格式如下：</p><div class="language-txt line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki github-dark"><code><span class="line"><span style="color:#e1e4e8;">主版本号.次版本号.修订号</span></span>
<span class="line"><span style="color:#e1e4e8;"></span></span>
<span class="line"><span style="color:#e1e4e8;">major.minor.patch</span></span>
<span class="line"><span style="color:#e1e4e8;"></span></span>
<span class="line"><span style="color:#e1e4e8;">X.Y.Z</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><ul><li>X 会在破坏性更新时 +1，此时会将 Y 和 Z 重置为 0。</li><li>Y 会在新增向下兼容的功能性时 +1，此时会将 Z 重置为 0。</li><li>Z 会在修正向下兼容的问题时 +1。</li></ul><p>当然，语义化版本也充分考虑了先行版本号和编译信息的问题。这不是这篇博客的重点，如果你感兴趣，可以点进博客开头的链接，阅读完整的文档。</p><h2 id="为什么要用语义化版本" tabindex="-1">为什么要用语义化版本 <a class="header-anchor" href="#为什么要用语义化版本" aria-label="Permalink to &quot;为什么要用语义化版本&quot;">​</a></h2><p>一方面，语义化版本方便了别人。用户无需特别翻看改动日志，从版本号的变化就能直观地了解是否存在破坏性更新。</p><p>另一方面，语义化版本方便了自己。你可以使用大量支持语义化版本的工具和库来开发和管理自己的工具和库。比起非语义化版本，你可以省去大量的时间。</p><p>更何况，语义化版本已经被广泛采用。打不过就加入是一个经验之谈（笑）。</p><h2 id="谁在用语义化版本" tabindex="-1">谁在用语义化版本 <a class="header-anchor" href="#谁在用语义化版本" aria-label="Permalink to &quot;谁在用语义化版本&quot;">​</a></h2><p>正如前面所说的，语义化版本已经被广泛采用。<code>npm</code>、<code>webpack</code>、<code>vite</code>、<code>rollup</code>、<code>antd</code> 等库就是遵循语义化版本的巨头。</p><h2 id="语义化版本的缺陷" tabindex="-1">语义化版本的缺陷 <a class="header-anchor" href="#语义化版本的缺陷" aria-label="Permalink to &quot;语义化版本的缺陷&quot;">​</a></h2><p>语义化版本是理想化的，版本号的变动实际上反映的是开发者的预想。实际上，修复一个问题或者新增一个功能，引出了另一个问题，这并不少见。</p><p>另外，<code>npm</code> 生态内也出现过通过语义化版本投毒的情况。比如 <code>^2.0.0</code> 允许主版本号为 2 的所有版本，如果在 <code>2.0.1</code> 版本投毒，用户是有可能中招的。这就只能锁定版本，在更新前检查依赖，这种信任问题需要付出额外的时间和精力来避免，实际上抹去了语义化版本的优势。</p><h2 id="其它的版本号方案" tabindex="-1">其它的版本号方案 <a class="header-anchor" href="#其它的版本号方案" aria-label="Permalink to &quot;其它的版本号方案&quot;">​</a></h2><p>Android 的版本号 <code>Version Code</code> 实际上就是一个正整数，每次发布新版本只需直接 +1，而版本名 <code>Version Name</code> 可以遵循语义化版本。</p><p>Jetbrains 家的产品使用年份、月份和编译信息作为版本号。</p><p>某些项目看着遵循语义化版本，但实际上并非如此，具体还是要根据官方表达为准。</p><h2 id="实践" tabindex="-1">实践 <a class="header-anchor" href="#实践" aria-label="Permalink to &quot;实践&quot;">​</a></h2><p>在 <code>npm</code> 生态中，有很多工具可以帮你实践语义化版本。</p><p>我最初使用的是 <a href="https://github.com/sindresorhus/np" target="_blank" rel="noreferrer">np</a>。这是一个简单的工具，在大部分场景下，它工作得很好。</p><p>在社区切换到 <code>pnpm</code> 的风潮之下，我也尝试了一下 <code>pnpm</code>，发现 <code>pnpm</code> 用起来非常舒服，打算切换到 <code>pnpm</code>。遗憾的是，我发现 <code>np</code> 对 <code>pnpm</code> 支持不是太好。所以，我转向使用另一个包 <a href="https://github.com/release-it/release-it" target="_blank" rel="noreferrer">release-it</a>。</p><p><code>release-it</code> 在大部分时间工作得很好，它也能支持 <code>monorepo</code>，就是需要手动配置一下。但我不是太喜欢它先 <code>publish</code> 到 <code>npm</code> 仓库再 <code>push</code> 到 <code>git</code> 仓库的行为，所以我转向使用 <a href="https://github.com/antfu/bumpp" target="_blank" rel="noreferrer">bumpp</a>。</p><p><code>bumpp</code> 非常轻量，只负责更新版本，不负责推测下一个语义化版本应该是什么，也不负责生成改动日志。我更喜欢使用一体化的方案，所以我后续又转向使用 <a href="https://github.com/absolute-version/commit-and-tag-version" target="_blank" rel="noreferrer">commit-and-tag-version</a>。</p><p>本篇是系列的第一篇，我建议你阅读完语义化版本（就是本篇）、<a href="./conventional-commits.html">约定式提交</a> 和 <a href="./changelog.html">改动日志</a> 再开始实践！😄</p>`,30),t=[s];function l(p,c,d,i,h,m){return o(),a("div",null,t)}const _=e(r,[["render",l]]);export{u as __pageData,_ as default};
